const payload = $json.body || $json;

const roundName = payload.interview_round || '';
const isFach = roundName.toLowerCase().includes('fach-');

if (!isFach) {
  throw new Error('Kein Fach- & Fit-Gespraech (Runde 2). Abbruch. Runde: ' + roundName);
}

const skills = payload.skill_assessment || [];
const averageRating = skills.length > 0
  ? parseFloat((skills.reduce((sum, s) => sum + (s.rating || 0), 0) / skills.length).toFixed(2))
  : 0;

const skillsText = skills.length > 0
  ? skills.map(function(s) {
      const name = s.skill || 'Unbekannt';
      const rating = s.rating != null ? s.rating : '-';
      return '- ' + name + ': ' + rating;
    }).join('\n')
  : 'Keine Skill-Bewertungen vorhanden';

function parseFeedbackSections(text) {
  const result = { overall: '', strengths: '', weaknesses: '', culture: '', logistics: '', other: '' };
  if (!text) return result;
  const lines = text.split('\n');
  let currentSection = 'overall';
  for (const line of lines) {
    const lower = line.trim().toLowerCase();
    if (lower.startsWith('gesamteindruck')) { currentSection = 'overall'; result.overall += line.trim() + '\n'; continue; }
    if (lower.startsWith('starken') || lower.startsWith('staerken')) { currentSection = 'strengths'; result.strengths += line.trim() + '\n'; continue; }
    if (lower.startsWith('schwachen') || lower.startsWith('schwaechen')) { currentSection = 'weaknesses'; result.weaknesses += line.trim() + '\n'; continue; }
    if (lower.startsWith('kultur')) { currentSection = 'culture'; result.culture += line.trim() + '\n'; continue; }
    if (lower.startsWith('logistik')) { currentSection = 'logistics'; result.logistics += line.trim() + '\n'; continue; }
    if (currentSection === 'overall') result.overall += line + '\n';
    else if (currentSection === 'strengths') result.strengths += line + '\n';
    else if (currentSection === 'weaknesses') result.weaknesses += line + '\n';
    else if (currentSection === 'culture') result.culture += line + '\n';
    else if (currentSection === 'logistics') result.logistics += line + '\n';
    else result.other += line + '\n';
  }
  return {
    overall: result.overall.trim(),
    strengths: result.strengths.trim(),
    weaknesses: result.weaknesses.trim(),
    culture: result.culture.trim(),
    logistics: result.logistics.trim(),
    other: result.other.trim()
  };
}

const sections = parseFeedbackSections(payload.feedback || '');

return {
  json: {
    applicant_id: payload.job_applicant || 'Unbekannt',
    position: payload.position || 'Unbekannt',
    round_name: roundName || 'Fach- & Fit-Gespraech',
    result: payload.result || 'Unbekannt',
    average_rating: averageRating,
    skill_assessments: skillsText,
    feedback: payload.feedback || '',
    feedback_sections: sections,
    raw_skill_assessment: skills,
    interview_id: payload.interview || '',
    feedback_id: payload.name || ''
  }
};

const r2 = $('aggregate_data_r2').first().json;

const r1Response = $('fetch_round1_data').first().json;
const r1Data = r1Response.data || r1Response;

const dsgvoConsent = r1Data.custom_dsgvo_scoring_zustimmung;
const datenschutzConsent = r1Data.custom_datenschutzhinweis_bewerber;

if (!dsgvoConsent || dsgvoConsent !== 1) {
  throw new Error('DSGVO Scoring-Zustimmung fehlt oder nicht erteilt (custom_dsgvo_scoring_zustimmung = ' + dsgvoConsent + '). Abbruch.');
}

if (!datenschutzConsent || datenschutzConsent !== 1) {
  throw new Error('Datenschutzhinweis-Zustimmung fehlt oder nicht erteilt (custom_datenschutzhinweis_bewerber = ' + datenschutzConsent + '). Abbruch.');
}

const r1SummaryRaw = r1Data.custom_interview_summary || '';
if (!r1SummaryRaw || r1SummaryRaw.trim() === '') {
  throw new Error('Keine Zusammenfassung aus Runde 1 vorhanden. Runde 1 wurde vermutlich nicht durchlaufen oder noch nicht zusammengefasst.');
}

const r1Passed = r1SummaryRaw.toLowerCase().includes('weiter zu runde 2');
if (!r1Passed) {
  throw new Error('Kandidat hat Runde 1 nicht bestanden. Fach- & Fit-Gespraech nicht zulaessig.');
}

const firstName = r1Data.custom_vorname || '';
const lastName = r1Data.applicant_name || '';
const applicantName = (firstName + ' ' + lastName).trim();

const r1Summary = r1SummaryRaw;
const r1Skills = r1Data.custom_skill_assessment || [];

const r1SkillsText = Array.isArray(r1Skills) && r1Skills.length > 0
  ? r1Skills.map(function(s) {
      const name = s.skill || 'Unbekannt';
      const rating = s.rating != null ? s.rating : '-';
      return '- ' + name + ': ' + rating;
    }).join('\n')
  : 'Keine Skill-Bewertungen aus Runde 1 vorhanden';

const cvSummary = r1Data.custom_zusammenfassung_cv || '';

const cvSkills = r1Data.custom_skills_und_technologien || [];
const cvSkillsText = Array.isArray(cvSkills) && cvSkills.length > 0
  ? cvSkills.map(function(s) {
      const tech = s.custom_cvskill_technologie || 'Unbekannt';
      const level = s.custom_cveinstufung || '-';
      return '- ' + tech + ': ' + level;
    }).join('\n')
  : 'Keine CV-Skills vorhanden';

const cvCareer = r1Data.custom_beruflicher_werdegang || [];
const cvCareerText = Array.isArray(cvCareer) && cvCareer.length > 0
  ? cvCareer.map(function(c) {
      const title = c.custom_cvjobtitel__position || 'Unbekannt';
      const company = c.custom_cvunternehmen || 'Unbekannt';
      const period = c.custom_cvzeitraum || '-';
      return '- ' + title + ' bei ' + company + ' (' + period + ')';
    }).join('\n')
  : 'Kein beruflicher Werdegang vorhanden';

const jobOpeningId = r1Data.job_title || '';

let jobDescription = '';
const jobOpeningNode = $('get_job_opening_r2');
if (jobOpeningNode) {
  const jobOpeningResponse = jobOpeningNode.first().json;
  const jd = jobOpeningResponse.data || jobOpeningResponse;
  if (jd && jd.doctype === 'Job Opening') {
    jobDescription = jd.description || jd.job_description || '';
  }
}

let interviewerName = '';
let interviewDate = '';
const interviewNode = $('get_interview_r2');
if (interviewNode) {
  const interviewResponse = interviewNode.first().json;
  const interviewData = interviewResponse.data || interviewResponse;
  if (interviewData && interviewData.doctype === 'Interview') {
    interviewDate = interviewData.scheduled_on || '';
    const details = interviewData.interview_details || [];
    if (details.length > 0) {
      interviewerName = details[0].interviewer || '';
    }
  }
}

const sections = r2.feedback_sections || {};
const feedbackStructuredR2 = sections.overall
  ? 'Gesamteindruck:\n' + sections.overall
    + (sections.strengths ? '\n\nStärken:\n' + sections.strengths : '')
    + (sections.weaknesses ? '\n\nSchwächen:\n' + sections.weaknesses : '')
    + (sections.culture ? '\n\nKultur:\n' + sections.culture : '')
    + (sections.logistics ? '\n\nLogistik:\n' + sections.logistics : '')
  : (r2.feedback || '');

const oldTechnicalSummary = r1Data.custom_summary_technical || '';
const oldTechnicalSkillAssessment = r1Data.custom_skill_assessment_technical || [];

return {
  json: {
    applicant_id: r2.applicant_id,
    applicant_name: applicantName,
    position: r2.position,
    round_name: r2.round_name,
    result: r2.result,
    average_rating_r2: r2.average_rating,
    skill_assessments_r2: r2.skill_assessments,
    feedback_r2: r2.feedback,
    feedback_sections_r2: r2.feedback_sections,
    feedback_structured_r2: feedbackStructuredR2,
    raw_skill_assessment_r2: r2.raw_skill_assessment,
    feedback_id_r2: r2.feedback_id,
    interview_id_r2: r2.interview_id,
    r1_summary: r1Summary,
    r1_skills_text: r1SkillsText,
    r1_raw_skills: r1Skills,
    r1_screening_feedback_id: r1Data.custom_screening_feedback || '',
    cv_summary: cvSummary,
    cv_skills: cvSkillsText,
    cv_career: cvCareerText,
    job_opening_id: jobOpeningId,
    job_description: jobDescription,
    interviewer_name: interviewerName,
    interview_date: interviewDate,
    old_summary_technical: oldTechnicalSummary,
    old_skill_assessment_technical: oldTechnicalSkillAssessment
  }
};

const llmOutput = $input.first().json.output || $input.first().json.text || $input.first().json.content;

if (!llmOutput) {
  throw new Error('Kein LLM Output. Felder: ' + Object.keys($input.first().json).join(', '));
}

const cleaned = llmOutput.replace(/```json/g, '').replace(/```/g, '').trim();

const aggr = $('aggregate_data_r2').first();
const combined = $('aggregate_r1_r2').first();
const jobApplicantId = aggr.json.applicant_id;
const rawSkills = aggr.json.raw_skill_assessment || [];
const result = aggr.json.result || '';
const feedbackId = aggr.json.feedback_id || '';
const interviewId = aggr.json.interview_id || '';

const interviewDate = combined ? combined.json.interview_date : '';
const interviewerName = combined ? combined.json.interviewer_name : '';
const processedDate = new Date().toISOString().split('T')[0];

let header = '=== Finale Interview-Bewertung ===\n';
header += 'Interview-ID: ' + (interviewId || feedbackId) + '\n';
if (interviewDate) header += 'Interview-Datum: ' + interviewDate + '\n';
header += 'Erstellt am: ' + processedDate + '\n';
if (interviewerName) header += 'Interviewer: ' + interviewerName + '\n';
header += '----------------------------------------\n\n';

const isCleared = result.toLowerCase() === 'cleared';

let output = header + cleaned;
output += '\n\n---\n';
output += 'Abschluss Fach- & Fit-Gespraech (Runde 2): ';
output += isCleared ? 'Einstellung empfohlen.' : 'Keine Einstellungsempfehlung.';

const skillAssessmentTable = rawSkills.map(function(s) {
  return {
    skill: s.skill || 'Unbekannt',
    rating: s.rating != null ? s.rating : 0
  };
});

const updatePayload = {
  custom_summary_technical: output,
  custom_skill_assessment_technical: skillAssessmentTable,
  custom_hard_and_softskills_feedback: feedbackId
};

if (combined && combined.json.old_summary_technical && combined.json.old_summary_technical.trim() !== '') {
  updatePayload.custom_summary_technical_history = JSON.stringify([
    {
      version: combined.json.feedback_id_r2 || 'unknown',
      date: processedDate,
      summary: combined.json.old_summary_technical,
      skills: combined.json.old_skill_assessment_technical || []
    }
  ]);
}

return {
  json: {
    job_applicant_id: jobApplicantId,
    update_payload: updatePayload
  }
};
